];
const SIT_DIST=[
  {name:"Normal",value:5279,color:"#eab308"},
  {name:"Heavy", value:1819,color:"#f97316"},
  {name:"Low",   value:1138,color:"#22c55e"},
  {name:"High",  value:692, color:"#ef4444"},
];
const FEAT_IMP=[
  {f:"Total Vehicles",imp:32.4},{f:"Car Count",imp:18.4},
  {f:"Truck Count",imp:14.3},{f:"Bus Count",imp:13.8},
  {f:"Truck+Bus Ratio",imp:8.2},{f:"Car Ratio",imp:5.0},
  {f:"Bike Count",imp:3.8},{f:"Hour of Day",imp:2.1},
];
const ALERTS_DATA=[
  {id:1,type:"Severe", icon:"🚨",loc:"NH-65 / HITEC City",      msg:"Heavy congestion — 89% load. Avg speed 12 km/h. Divert via ORR.",   time:"1 min ago", color:"#ef4444"},
  {id:2,type:"Warning",icon:"⚠️",loc:"Mehdipatnam Junction",    msg:"Signal fault. Manual control active. Expect +15 min delay.",         time:"4 min ago", color:"#f97316"},
  {id:3,type:"Warning",icon:"🌧️",loc:"LB Nagar Flyover",        msg:"Heavy rain reduces visibility. Speed avg 18 km/h.",                  time:"7 min ago", color:"#f97316"},
  {id:4,type:"Info",   icon:"✅",loc:"Outer Ring Road",          msg:"Adaptive signals cut average wait by 24% in last hour.",             time:"12 min ago",color:"#3b82f6"},
  {id:5,type:"Info",   icon:"🚧",loc:"Secunderabad Station Rd",  msg:"Road resurfacing between James St and SD Rd. One lane closed.",     time:"18 min ago",color:"#eab308"},
  {id:6,type:"Severe", icon:"🚨",loc:"Charminar Old City",       msg:"Festival crowd. 95% congestion. All routes affected. Avoid area.",  time:"22 min ago",color:"#ef4444"},
];

/* ═══════════════════════════════════════════════════════════════
   ML — RF SIMULATION (mirrors your Python backend)
═══════════════════════════════════════════════════════════════ */
const SIT_COLOR={low:"#22c55e",normal:"#eab308",heavy:"#f97316",high:"#ef4444"};
const SIT_SCORE={low:18,normal:42,heavy:68,high:88};

function rfPredict({hour,cars,bikes,buses,trucks}){
  const total=cars+bikes+buses+trucks;
  const peak=(hour>=7&&hour<=9)||(hour>=16&&hour<=19)?1:0;
  const tbr=(trucks+buses)/(total+1);
  let s=(total/180)*52+peak*26+tbr*14+(Math.random()*8-4);
  s=Math.max(5,Math.min(97,Math.round(s)));
  const sit=s<30?"low":s<55?"normal":s<75?"heavy":"high";
  return{score:s,sit,color:SIT_COLOR[sit],speed:Math.round(Math.max(8,65-s*0.57)),delay:Math.round(s/3.4),conf:Math.round(88+Math.random()*9),total};
}

function scoreFromHour(hour){
  const row=REAL_HOURLY[hour]||REAL_HOURLY[8];
  return Math.round((row.total/180)*78);
}

function buildLiveEdges(hour){
  return EDGES.map(e=>{
    const base=scoreFromHour(hour);
    const sc=Math.max(5,Math.min(97,base+Math.round((Math.random()-.5)*24)));
    const col=sc<30?"#22c55e":sc<55?"#eab308":sc<75?"#f97316":"#ef4444";
    const spd=Math.round(Math.max(8,e.speedLimit-(sc/100)*(e.speedLimit-8)));
    return{...e,score:sc,color:col,speed:spd,delay:Math.round(sc/3.4)};
  });
}

/* ═══════════════════════════════════════════════════════════════
   DIJKSTRA — Shortest Path weighted by travel time
═══════════════════════════════════════════════════════════════ */
function dijkstra(liveEdges,start,end){
  const graph={};
  liveEdges.forEach(e=>{
    if(!graph[e.from])graph[e.from]=[];
    if(!graph[e.to])  graph[e.to]=[];
    const tt=(e.km/Math.max(5,e.speed))*60;// minutes
    graph[e.from].push({node:e.to,  cost:tt,km:e.km,score:e.score,color:e.color,name:e.name,speed:e.speed});
    graph[e.to].push(  {node:e.from,cost:tt,km:e.km,score:e.score,color:e.color,name:e.name,speed:e.speed});
  });
  const dist={},prev={},vis=new Set();
  Object.keys(LOCATIONS).forEach(n=>dist[n]=Infinity);
  dist[start]=0;
  const pq=[[0,start]];
  while(pq.length){
    pq.sort((a,b)=>a[0]-b[0]);
    const[d,u]=pq.shift();
    if(vis.has(u))continue;vis.add(u);
    if(u===end)break;
    (graph[u]||[]).forEach(({node,cost,km,score,color,name,speed})=>{
      const nd=d+cost;
      if(nd<dist[node]){dist[node]=nd;prev[node]={from:u,cost,km,score,color,name,speed};pq.push([nd,node]);}
    });
  }
  const path=[];let cur=end;
  while(cur){path.unshift(cur);cur=prev[cur]?.from;}
  const segs=path.slice(1).map((n,i)=>({from:path[i],to:n,...prev[n]}));
  const totalKm=segs.reduce((a,s)=>a+(s.km||0),0);
  return{path,segs,totalTime:Math.round(dist[end]||0),totalKm:Math.round(totalKm*10)/10};
}

/* ═══════════════════════════════════════════════════════════════
   GOOGLE MAP COMPONENT
═══════════════════════════════════════════════════════════════ */
function GoogleMap({liveEdges,route,origin,dest,onMarkerClick}){
  const ref=useRef(null);
  const mapRef=useRef(null);
  const drawn=useRef([]);

  const DARK_STYLE=[
    {elementType:"geometry",          stylers:[{color:"#0d1b2e"}]},
    {elementType:"labels.text.fill",  stylers:[{color:"#7aa3c8"}]},
    {elementType:"labels.text.stroke",stylers:[{color:"#0d1b2e"}]},
    {featureType:"road",              elementType:"geometry",        stylers:[{color:"#1a3a5c"}]},
    {featureType:"road",              elementType:"geometry.stroke", stylers:[{color:"#0f2540"}]},
    {featureType:"road",              elementType:"labels.text.fill",stylers:[{color:"#8baabf"}]},
    {featureType:"road.highway",      elementType:"geometry",        stylers:[{color:"#1a4a8a"}]},
    {featureType:"road.highway",      elementType:"labels.text.fill",stylers:[{color:"#aac8e0"}]},
    {featureType:"water",             elementType:"geometry",        stylers:[{color:"#0a1c30"}]},
    {featureType:"poi",               stylers:[{visibility:"off"}]},
    {featureType:"transit",           stylers:[{visibility:"simplified"}]},
    {featureType:"landscape",         elementType:"geometry",        stylers:[{color:"#0d1b2e"}]},
    {featureType:"administrative",    elementType:"geometry.stroke", stylers:[{color:"#1e3a5f"}]},
  ];

  function initMap(){
    if(!ref.current||mapRef.current)return;
    mapRef.current=new window.google.maps.Map(ref.current,{
      center:{lat:17.406,lng:78.477},
      zoom:12,
      styles:DARK_STYLE,
      mapTypeControl:false,
      streetViewControl:false,
      fullscreenControl:true,
      zoomControl:true,
    });
    redraw();
  }

  function clearDrawn(){
    drawn.current.forEach(o=>{try{o.setMap(null);}catch(e){}});
    drawn.current=[];
  }

  function redraw(){
    if(!mapRef.current||!window.google)return;
    clearDrawn();
    const G=window.google,map=mapRef.current;
    const routeEdgeSet=new Set((route?.segs||[]).flatMap(s=>[`${s.from}-${s.to}`,`${s.to}-${s.from}`]));

    // ── Draw all road segments ──
    liveEdges.forEach(e=>{
      const A=LOCATIONS[e.from],B=LOCATIONS[e.to];
      if(!A||!B)return;
      const isR=routeEdgeSet.has(`${e.from}-${e.to}`);
      // Shadow
      const shadow=new G.maps.Polyline({
        path:[{lat:A.lat,lng:A.lng},{lat:B.lat,lng:B.lng}],
        strokeColor:isR?"#1d4ed8":e.color,
        strokeOpacity:.18,strokeWeight:isR?18:10,map,zIndex:1
      });
      // Main line
      const line=new G.maps.Polyline({
        path:[{lat:A.lat,lng:A.lng},{lat:B.lat,lng:B.lng}],
        strokeColor:isR?"#60a5fa":e.color,
        strokeOpacity:isR?1:.65,strokeWeight:isR?6:3.5,
        map,zIndex:isR?10:2,
        icons:isR?[{icon:{path:G.maps.SymbolPath.FORWARD_CLOSED_ARROW,scale:3.5,strokeColor:"#93c5fd",fillColor:"#93c5fd",fillOpacity:1},offset:"100%",repeat:"90px"}]:[]
      });
      const iw=new G.maps.InfoWindow({
        content:`<div style="background:#0d1b2e;color:#e2e8f0;padding:14px 18px;border-radius:10px;font-family:'IBM Plex Sans',sans-serif;min-width:220px;border:1px solid #1e3a5f">
          <div style="font-size:9px;color:#5a7098;letter-spacing:2px;margin-bottom:6px">ROAD SEGMENT${isR?" · ✦ BEST ROUTE":""}</div>
          <div style="font-weight:700;font-size:14px;margin-bottom:12px;color:#f1f5f9">${e.name}</div>
          <div style="display:grid;grid-template-columns:1fr 1fr;gap:8px">
            <div style="background:#0a1628;border-radius:6px;padding:8px;text-align:center">
              <div style="font-size:9px;color:#5a7098">CONGESTION</div>
              <div style="font-size:18px;font-weight:700;color:${e.color};font-family:monospace">${e.score}%</div>
            </div>
            <div style="background:#0a1628;border-radius:6px;padding:8px;text-align:center">
              <div style="font-size:9px;color:#5a7098">SPEED</div>
              <div style="font-size:18px;font-weight:700;color:#22c55e;font-family:monospace">${e.speed}<span style="font-size:10px">km/h</span></div>
            </div>
            <div style="background:#0a1628;border-radius:6px;padding:8px;text-align:center">
              <div style="font-size:9px;color:#5a7098">DELAY</div>
              <div style="font-size:18px;font-weight:700;color:#f97316;font-family:monospace">+${e.delay}<span style="font-size:10px">min</span></div>
            </div>
            <div style="background:#0a1628;border-radius:6px;padding:8px;text-align:center">
              <div style="font-size:9px;color:#5a7098">LIMIT</div>
              <div style="font-size:18px;font-weight:700;color:#94a3b8;font-family:monospace">${e.speedLimit}<span style="font-size:10px">km/h</span></div>
            </div>
          </div>
        </div>`
      });
      line.addListener("click",ev=>{iw.setPosition(ev.latLng);iw.open(map);});
      drawn.current.push(shadow,line);
    });

    // ── Draw route path highlight ──
    if(route?.path?.length>1){
      const pts=route.path.map(id=>({lat:LOCATIONS[id]?.lat,lng:LOCATIONS[id]?.lng})).filter(p=>p.lat);
      const glow=new G.maps.Polyline({path:pts,strokeColor:"#3b82f6",strokeOpacity:.15,strokeWeight:28,map,zIndex:8});
      drawn.current.push(glow);
    }

    // ── Draw markers for all junctions ──
    Object.values(LOCATIONS).forEach(loc=>{
      const isO=loc.id===origin,isD=loc.id===dest,isR=route?.path?.includes(loc.id);
      const col=isO?"#22c55e":isD?"#f97316":isR?"#60a5fa":"#4a6a8a";
      const scale=isO||isD?16:isR?12:8;
      const label=isO?"A":isD?"B":null;

      const marker=new G.maps.Marker({
        position:{lat:loc.lat,lng:loc.lng},
        map,title:loc.name,
        label:label?{text:label,color:"#fff",fontWeight:"bold",fontSize:"12px"}:null,
        icon:{
          path:G.maps.SymbolPath.CIRCLE,
          scale,fillColor:col,fillOpacity:.92,
          strokeColor:"#ffffff",strokeWeight:isO||isD?2.5:1.5,
        },
        zIndex:isO||isD?30:isR?20:5,
      });

      const iw=new G.maps.InfoWindow({
        content:`<div style="background:#0d1b2e;color:#e2e8f0;padding:12px 16px;border-radius:10px;font-family:'IBM Plex Sans',sans-serif;border:1px solid #1e3a5f;min-width:180px">
          <div style="font-size:9px;color:#5a7098;letter-spacing:2px;margin-bottom:4px">${loc.zone.toUpperCase()}</div>
          <div style="font-weight:700;font-size:14px;color:#f1f5f9;margin-bottom:6px">${loc.name}</div>
          <div style="font-size:11px;color:${col}">${isO?"🟢 ORIGIN — Start point":isD?"🟠 DESTINATION — End point":isR?"🔵 On shortest path":"📍 Junction node"}</div>
        </div>`
      });
      marker.addListener("click",()=>{iw.open(map,marker);onMarkerClick(loc.id);});
      drawn.current.push(marker);
    });
  }

  // Load Google Maps once
  useEffect(()=>{
    if(window.google){initMap();return;}
    if(document.getElementById("gms")){
      const s=document.getElementById("gms");
      const old=s.onload;
      s.onload=()=>{if(old)old();initMap();};
      return;
    }
    const s=document.createElement("script");
    s.id="gms";
    s.src=`https://maps.googleapis.com/maps/api/js?key=${GMAPS_KEY}`;
    s.async=true; s.onload=initMap;
    document.head.appendChild(s);
  },[]);

  // Redraw when data changes
  useEffect(()=>{
    if(mapRef.current&&window.google)redraw();
  },[liveEdges,route,origin,dest]);

  return(
    <div style={{position:"relative",borderRadius:12,overflow:"hidden",border:"1px solid #1a2744"}}>
      <div ref={ref} style={{width:"100%",height:520}}/>
      {/* Legend overlay */}
      <div style={{position:"absolute",bottom:14,left:14,background:"rgba(13,27,46,.93)",border:"1px solid #1e3a5f",borderRadius:10,padding:"12px 16px",backdropFilter:"blur(8px)"}}>
        <div style={{fontSize:9,color:"#5a7098",letterSpacing:2,marginBottom:8,fontFamily:"'IBM Plex Sans',sans-serif"}}>CONGESTION INDEX</div>
        {[["#22c55e","Low  < 30%"],["#eab308","Normal 30–55%"],["#f97316","Heavy 55–75%"],["#ef4444","High  > 75%"],["#60a5fa","◀ Shortest Path"]].map(([c,l])=>(
          <div key={l} style={{display:"flex",alignItems:"center",gap:8,marginBottom:5}}>
            <div style={{width:26,height:5,borderRadius:3,background:c}}/>
            <span style={{fontSize:10,color:"#94a3b8",fontFamily:"'IBM Plex Sans',sans-serif"}}>{l}</span>
          </div>
        ))}
      </div>
      {/* Live badge */}
      <div style={{position:"absolute",top:12,left:14,background:"rgba(13,27,46,.9)",border:"1px solid #22c55e44",borderRadius:7,padding:"5px 12px",display:"flex",alignItems:"center",gap:7}}>
        <div style={{width:7,height:7,borderRadius:"50%",background:"#22c55e",animation:"pu 2s infinite"}}/>
        <span style={{fontSize:10,color:"#22c55e",fontWeight:700,fontFamily:"'IBM Plex Sans',sans-serif"}}>LIVE · Hyderabad Traffic</span>
      </div>
      {/* RF badge */}
      <div style={{position:"absolute",top:12,right:14,background:"rgba(13,27,46,.9)",border:"1px solid #3b82f644",borderRadius:7,padding:"5px 12px"}}>
        <span style={{fontSize:10,color:"#3b82f6",fontWeight:700,fontFamily:"'IBM Plex Sans',sans-serif"}}>🤖 RF Model · 92.89% Accuracy</span>
      </div>
    </div>
  );
}

